require('dotenv').config();
const fs = require('fs');
const Inconvo = require('@inconvoai/node');

async function main() {
  const client = new Inconvo.default({
    apiKey: process.env.INCONVO_API_KEY,
    agentId: process.env.INCONVO_AGENT_ID,
  });

  // Create a new conversation
  const conversation = await client.conversations.create({
    context: { user_id: 123 },
  });

  const { id } = conversation;

  // Send a message to the conversation
  const response = await client.conversations.messages.create(id, {
    message: 'What are my top products?',
  });

  // Save the response to response.json
  fs.writeFileSync(
    'response.json',
    JSON.stringify(response, null, 2),
    'utf-8'
  );

  console.log('Response saved to response.json');
}

main().catch((err) => {
  console.error('Error:', err);
  process.exit(1);
});

